<Stats id="monster-herald_the_first_blade--stats" atts={[32,13,28,10,15,13]} bab={18} cmb={30} cmbP="+32 bull rush or overrun" cmd={41} cmdP="43 vs. bull rush or overrun" feats={["Blind-Fight","Cleave","Combat Reflexes","Great Cleave","Improved Bull Rush","Improved Initiative","Improved Overrun","Power Attack",["Weapon Focus"," (slam)"]]} skills={{"acro":{"b":22},"climb":{"b":32},"intm":{"b":22},"k":{"h":21},"per":{"b":23},"sm":{"b":23}}} lang={["A","Ce","C","I","P"]} sq={<><Link to="/umr/change_shape">change shape</Link> (swarm form; see below)<sup>C</sup>, lord of battle, <Link to="/umr/no_breath">no breath</Link></>} />
