<Offense id="monster-herald_the_grand_defender--offense" sp={30} melee="warhammer +27/+22/+17/+12 (3d6+11/&times;3)" space={"15"} reach={"15"} specAtt={[["breath weapon","breath weapon"],["hammer storm","hammer storm"]]} />
