<Stats id="monster-ilzunae--stats" atts={[0,22,22,14,20,26]} bab={18} cmb={24} cmd={44} feats={["Blind-Fight","Combat Expertise","Demonic Obedience","Dodge","Eschew Materials","Improved Possession","Lightning Stance","Mobility","Quicken Spell","Spring Attack","Toughness","Wind Stance"]} skills={{"bluff":{"b":33},"diplo":{"b":33},"sm":{"b":23}}} lang={["A","D",";",[<><Link to="/umr/telepathy">telepathy</Link> 100 ft.</>]]} sq="eyes of darkness (7 rounds/day)" gear={[["+5","EGL","EGA","Asl"],["IOdeep red sphere"],["IOdusty rose prism"],["IOpink and green sphere"],["IOpink rhomboid"],["WI-manual of bodily health +1/used"]]} />
