<Defense id="monster-kaiju_bezravnis--defense" ac={[44,7,39]} mod="+5 Dex, +37 natural, -8 size" hp={[615,"30d10+450"]} fh="30" fort="+32" ref="+24" will="+20" def={[["recovery","recovery"]]} ferocity dr="20/epic" immune="ability damage, ability drain, death effects, disease, energy drain, fear, fire" resist="acid 30, cold 30, electricity 30, negative energy 30, sonic 30" />
