<Stats id="monster-kaiju_bezravnis--stats" atts={[47,20,40,3,26,23]} bab={30} cmb={56} cmbP="+60 bull rush, +60 grapple" cmd={71} cmdP="73 vs. bull rush, 83 vs. trip" feats={["Combat Reflexes","Critical Focus","Greater Bull Rush","Greater Vital Strike","Improved Bull Rush",["Improved Critical"," (claw)"],"Improved Critical (sting)","Improved Initiative","Improved Lightning Reflexes","Improved Vital Strike","Iron Will","Lightning Reflexes","Power Attack","Staggering Critical","Vital Strike"]} skills={{"climb":{"b":31},"per":{"b":37},"stl":{"b":2,"x":"+32 when burrowing"}}} racial="+16 Perception, +30 Stealth when burrowing" lang={["TX"]} sq={<>massive, <Link to="/umr/no_breath">no breath</Link></>} />
